    internal class BasicHCSDataGenerator : IDataGenerator
    {
        Random random;

        public BasicHCSDataGenerator(Random random)
        {
            this.random = random;
        }

        // TODO: this is just temporary likely redo this based on how/where/when we are getting data from
        public string GenerateData(bool isValid)
        {

            JObject HCSBundleJObject = JObject.Parse(BaseHCSBundle);

            //update the file timestamp to current time
            HCSBundleJObject["timestamp"] = DateTime.Now.ToString("o");
            //get the content bundle
            JObject HCSContentBundleResourcesJObject = HCSBundleJObject["entry"][1]["resource"].Value<JObject>();

            // -------- First FHIR Resource: Patient --------
            JObject HCSPatientJObject = HCSContentBundleResourcesJObject["entry"][2]["resource"].Value<JObject>();
            //  "resource.name.0.text": "DOY, ZARLA MOON",
            //  "resource.name.0.family": "DOY",
            //  "resource.name.0.given.0": "ZARLA",
            //  "resource.name.0.given.1": "MOON",
            string randomFirstName = getRandomStringFromList(AvailableNames);
            string randomMiddleName = getRandomStringFromList(AvailableNames);
            string randomLastName = getRandomStringFromList(AvailableNames);
            string randomFullName = $"{randomLastName}, {randomFirstName} {randomMiddleName}";
            HCSPatientJObject["name"][0]["given"][0] = randomFirstName;
            HCSPatientJObject["name"][0]["given"][1] = randomMiddleName;
            HCSPatientJObject["name"][0]["family"] = randomLastName;
            HCSPatientJObject["name"][0]["text"] = randomFullName;
            //  "resource.telecom.0.value": "6166765017",
            HCSPatientJObject["telecom"][0]["value"] = getRandomDigitString(10);
            //  "resource.gender": "female",
            HCSPatientJObject["gender"] = getRandomStringFromList(AvailableGenders);
            //  "resource.birthDate": "1954-03-22",
            HCSPatientJObject["birthDate"] = $"{random.Next(1940, 2022)}-0{random.Next(1, 9)}-{random.Next(10, 28)}";
            //  "resource.address.0.text": "79 Roth Alley\nGrand Rapids, MI 49505\nUS",
            //  "resource.address.0.line.0": "79 Roth Alley",
            //  "resource.address.0.city": "Grand Rapids",
            //  "resource.address.0.state": "MI",
            //  "resource.address.0.postalCode": "49505",
            string randomStreet = getRandomStringFromList(AvailableStreets); ;
            string randomCity = getRandomStringFromList(AvailableCities);
            string randomState = getRandomStringFromList(AvailableStates);
            string randomPostalCode = getRandomDigitString(5);
            HCSPatientJObject["address"][0]["text"] = $"{randomStreet}\n{randomCity}, {randomState} {randomPostalCode}\nUS";
            HCSPatientJObject["address"][0]["line"][0] = randomStreet;
            HCSPatientJObject["address"][0]["city"] = randomCity;
            HCSPatientJObject["address"][0]["state"] = randomState;
            HCSPatientJObject["address"][0]["postalCode"] = randomPostalCode;
            //  "resource.generalPractitioner.0.display": "McGucken, Francoise"
            HCSPatientJObject["generalPractitioner"][0]["display"] = $"{getRandomStringFromList(AvailableNames)},{getRandomStringFromList(AvailableNames)}";

            // -------- Second FHIR Resource: Encounter --------
            JObject HCSEncounterJObject = HCSContentBundleResourcesJObject["entry"][1]["resource"].Value<JObject>();



            // If this bundle needs to be made invalid, mess up a property name
            string randomizedBundle = HCSBundleJObject.ToString();
            if (!isValid)
            {
                // make the bundle invalid

                // find a property, then add a random character
                string randomSubstringToFind = "\":";
                List<int> indexes = new List<int>();
                for (int index = 0; ; index += randomSubstringToFind.Length)
                {
                    index = randomizedBundle.IndexOf(randomSubstringToFind, index);
                    if (index == -1)
                        break;
                    indexes.Add(index);
                }
                int randomIndexToMessUp = indexes[random.Next(0, indexes.Count)] - 2;
                randomizedBundle = randomizedBundle.Remove(randomIndexToMessUp, 2).Insert(randomIndexToMessUp, getRandomDigitString(2));
            }


            return randomizedBundle;
        }



